import requests

BASE_URL = "http://localhost:5144"
LOGIN_PATH = "/api/v1/auth/login"
TIMEOUT = 30

def test_post_apiv1authlogin_valid_and_invalid_credentials():
    url = BASE_URL + LOGIN_PATH
    headers = {"Content-Type": "application/json"}

    # Test valid credentials
    valid_payload = {
        "username": "admin",
        "password": "Edrees1222004"
    }
    try:
        valid_response = requests.post(url, json=valid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Valid credentials request failed: {e}"

    assert valid_response.status_code == 200, f"Expected status 200 for valid credentials, got {valid_response.status_code}"
    try:
        valid_json = valid_response.json()
    except ValueError:
        assert False, "Response for valid credentials is not valid JSON"
    assert "accessToken" in valid_json and isinstance(valid_json["accessToken"], str) and valid_json["accessToken"].strip() != "", \
        "accessToken missing or empty in valid login response"
    assert "refreshToken" in valid_json and isinstance(valid_json["refreshToken"], str) and valid_json["refreshToken"].strip() != "", \
        "refreshToken missing or empty in valid login response"

    # Test invalid credentials
    invalid_payload = {
        "username": "admin",
        "password": "WrongPassword123"
    }
    try:
        invalid_response = requests.post(url, json=invalid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Invalid credentials request failed: {e}"

    assert invalid_response.status_code == 401, f"Expected status 401 for invalid credentials, got {invalid_response.status_code}"

test_post_apiv1authlogin_valid_and_invalid_credentials()

import requests

BASE_URL = "http://localhost:5144"
LOGIN_URL = f"{BASE_URL}/api/v1/auth/login"
SAMPLES_URL = f"{BASE_URL}/api/v1/samples"

ADMIN_USERNAME = "admin"
ADMIN_PASSWORD = "Edrees1222004"
TIMEOUT = 30

def test_post_apiv1samples_with_valid_and_invalid_data():
    # Step 1: Authenticate as admin to get access token
    login_payload = {"username": ADMIN_USERNAME, "password": ADMIN_PASSWORD}
    try:
        login_resp = requests.post(LOGIN_URL, json=login_payload, timeout=TIMEOUT)
        assert login_resp.status_code == 200, f"Login failed: {login_resp.text}"
        login_data = login_resp.json()
        access_token = login_data.get("accessToken")
        assert access_token, "accessToken not in login response"
    except Exception as e:
        raise AssertionError(f"Failed to login and retrieve access token: {e}")

    headers = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}

    # Step 2: POST with valid data - should return 201
    valid_payload = {
        "analysisRequestNumber": "AR123456",
        "sender": "Test Sender",
        "samples": [
            {
                "sampleNumber": "S001",
                "description": "Test sample 1",
                "root": "soil"
            },
            {
                "sampleNumber": "S002",
                "description": "Test sample 2",
                "root": "water"
            }
        ]
    }
    created_sample_id = None
    try:
        resp_valid = requests.post(SAMPLES_URL, json=valid_payload, headers=headers, timeout=TIMEOUT)
        assert resp_valid.status_code == 201, f"Expected 201 Created for valid data, got {resp_valid.status_code}, response: {resp_valid.text}"
        resp_json = resp_valid.json()
        # Validate response contains expected keys (at least analysisRequestNumber and samples)
        assert "analysisRequestNumber" in resp_json and resp_json["analysisRequestNumber"] == valid_payload["analysisRequestNumber"]
        assert "samples" in resp_json and isinstance(resp_json["samples"], list)
        created_sample_id = resp_json.get("id")  # id might be present to reference for cleanup
    except Exception as e:
        raise AssertionError(f"POST with valid data failed: {e}")

    # Step 3: POST with invalid data (missing analysisRequestNumber) - should return 400
    invalid_payload = {
        # "analysisRequestNumber": missing
        "sender": "Test Sender",
        "samples": [
            {
                "sampleNumber": "S003",
                "description": "Invalid sample",
                "root": "soil"
            }
        ]
    }
    try:
        resp_invalid = requests.post(SAMPLES_URL, json=invalid_payload, headers=headers, timeout=TIMEOUT)
        assert resp_invalid.status_code == 400, f"Expected 400 Validation Error for missing analysisRequestNumber, got {resp_invalid.status_code}, response: {resp_invalid.text}"
    except Exception as e:
        raise AssertionError(f"POST with invalid data did not return 400 as expected: {e}")

    # Cleanup: Delete the created sample reception if possible
    if created_sample_id:
        delete_url = f"{SAMPLES_URL}/{created_sample_id}"
        try:
            resp_del = requests.delete(delete_url, headers=headers, timeout=TIMEOUT)
            # Accept 204 No Content or 200 OK or 202 Accepted as successful deletes, or 404 if already removed
            assert resp_del.status_code in (204, 200, 202, 404)
        except Exception:
            pass  # Ignore cleanup failures

test_post_apiv1samples_with_valid_and_invalid_data()

import requests


BASE_URL = "http://localhost:5144"
LOGIN_URL = f"{BASE_URL}/api/v1/auth/login"
SAMPLES_URL = f"{BASE_URL}/api/v1/samples"
TIMEOUT = 30


def test_get_apiv1samples_with_valid_and_invalid_tokens():
    # Step 1: Login to get a valid access token
    login_payload = {
        "username": "admin",
        "password": "Edrees1222004"
    }
    try:
        login_response = requests.post(LOGIN_URL, json=login_payload, timeout=TIMEOUT)
        assert login_response.status_code == 200, f"Login failed with status {login_response.status_code}"
        login_json = login_response.json()
        access_token = login_json.get("accessToken")
        assert access_token and isinstance(access_token, str), "accessToken not found or invalid in login response"
    except requests.RequestException as e:
        assert False, f"Exception during login request: {e}"

    # Step 2: Call GET /api/v1/samples with valid token
    headers = {"Authorization": f"Bearer {access_token}"}
    try:
        samples_response = requests.get(SAMPLES_URL, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Exception during GET /api/v1/samples with valid token: {e}"

    assert samples_response.status_code == 200, f"Expected 200 OK with valid token, got {samples_response.status_code}"
    try:
        samples_json = samples_response.json()
    except Exception as e:
        assert False, f"Response not valid JSON: {e}"

    # Validate response contains top-level keys 'items' and 'totalCount'
    assert isinstance(samples_json, dict), "Response JSON is not an object"
    assert 'items' in samples_json, "'items' key missing in response"
    assert 'totalCount' in samples_json, "'totalCount' key missing in response"

    # Validate 'items' is a list
    assert isinstance(samples_json['items'], list), "'items' is not a list"

    # Step 3: Call GET /api/v1/samples with missing token
    try:
        no_auth_response = requests.get(SAMPLES_URL, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Exception during GET /api/v1/samples without token: {e}"

    assert no_auth_response.status_code == 401, f"Expected 401 Unauthorized without token, got {no_auth_response.status_code}"

    # Step 4: Call GET /api/v1/samples with invalid/expired token
    invalid_headers = {"Authorization": "Bearer invalid_or_expired_token"}
    try:
        invalid_token_response = requests.get(SAMPLES_URL, headers=invalid_headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Exception during GET /api/v1/samples with invalid token: {e}"

    assert invalid_token_response.status_code == 401, f"Expected 401 Unauthorized with invalid token, got {invalid_token_response.status_code}"


test_get_apiv1samples_with_valid_and_invalid_tokens()

import requests

BASE_URL = "http://localhost:5144"
LOGIN_URL = f"{BASE_URL}/api/v1/auth/login"
SETTINGS_SYSTEM_URL = f"{BASE_URL}/api/v1/settings/system"
ADMIN_USERNAME = "admin"
ADMIN_PASSWORD = "Edrees1222004"


def test_get_apiv1settingssystem_with_and_without_authorization():
    # Step 1: Login to get access token
    login_payload = {
        "username": ADMIN_USERNAME,
        "password": ADMIN_PASSWORD
    }
    try:
        login_response = requests.post(
            LOGIN_URL,
            json=login_payload,
            timeout=30
        )
    except requests.RequestException as e:
        assert False, f"Login request failed: {e}"
    assert login_response.status_code == 200, f"Login failed with status code {login_response.status_code}"
    login_data = login_response.json()
    assert "accessToken" in login_data and login_data["accessToken"], "accessToken missing in login response"
    access_token = login_data["accessToken"]

    headers_with_auth = {
        "Authorization": f"Bearer {access_token}"
    }

    # Step 2: Access /api/v1/settings/system WITH Authorization header - expect 200 and valid SystemSettings
    try:
        auth_response = requests.get(
            SETTINGS_SYSTEM_URL,
            headers=headers_with_auth,
            timeout=30
        )
    except requests.RequestException as e:
        assert False, f"Authorized GET /api/v1/settings/system request failed: {e}"

    assert auth_response.status_code == 200, f"Authorized request expected 200, got {auth_response.status_code}"

    # Basic validation that response JSON contains SystemSettings keys (as per system settings meaning assume keys)
    try:
        system_settings = auth_response.json()
    except ValueError:
        assert False, "Authorized response is not a valid JSON"

    assert isinstance(system_settings, dict) and len(system_settings) > 0, "SystemSettings response should be a non-empty JSON object"

    # Step 3: Access /api/v1/settings/system WITHOUT Authorization header - expect 401
    try:
        no_auth_response = requests.get(
            SETTINGS_SYSTEM_URL,
            timeout=30
        )
    except requests.RequestException as e:
        assert False, f"Unauthorized GET /api/v1/settings/system request failed: {e}"

    assert no_auth_response.status_code == 401, (
        f"Unauthorized request expected 401, got {no_auth_response.status_code}"
    )


test_get_apiv1settingssystem_with_and_without_authorization()
